def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    if len(prs.slides) < 2:
        return "Presentation has fewer than 2 slides.", 0.0
    slide = prs.slides[1]
    # Try to find title shape per slide layout
    title_shape = None
    for shape in slide.shapes:
        if shape.has_text_frame and shape.text_frame is not None:
            if shape == slide.shapes.title:
                title_shape = shape
                break
    if title_shape is None:
        # fallback: look for largest text box on slide with title-like text
        title_shape = None
        max_size = 0
        for shape in slide.shapes:
            if shape.has_text_frame and shape.text_frame is not None:
                if len(shape.text) > max_size:
                    title_shape = shape
                    max_size = len(shape.text)
        if title_shape is None:
            return "No title textbox found on second slide.", 0.0
    # Check all runs in title shape for font size
    all_runs = []
    for para in title_shape.text_frame.paragraphs:
        all_runs.extend(para.runs)
    if not all_runs:
        return "No text runs found in title textbox.", 0.0
    correct = True
    for run in all_runs:
        if run.font.size is None or abs(run.font.size.pt - 36) > 0.5:
            correct = False
    if not correct:
        return "Not all runs in the title textbox on the second slide are 36pt.", 0.0
    return "Title textbox on second slide is 36pt.", 1.0
